      expected_patterns: ['order status', 'ticket created', 'escalation required']
    }),
    new PIIFilter({ sensitive_fields: ['ssn', 'credit_card', 'account_number'] }),
    new ToneConsistency({ style: 'professional, empathetic, customer-focused' }),
